Use ASP.NET Core's **`WebApplicationFactory<T>`** — it hosts your app in-process with a test HTTP client, no real port needed.

### Setup

```bash
dotnet add package Microsoft.AspNetCore.Mvc.Testing
dotnet add package xunit
```

### Example test

```csharp
public class McpTests : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly HttpClient _client;

    public McpTests(WebApplicationFactory<Program> factory)
    {
        _client = factory.CreateClient();
    }

    [Fact]
    public async Task Initialize_ReturnsCapabilities()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test", version = "1.0" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.Equal("2025-03-26",
            body.GetProperty("result")
                .GetProperty("protocolVersion")
                .GetString());
    }

    [Fact]
    public async Task ToolsCall_ReturnsExpectedResult()
    {
        // Initialize first (required by MCP)
        await InitializeAsync();

        var request = new
        {
            jsonrpc = "2.0",
            id = 2,
            method = "tools/call",
            @params = new
            {
                name = "my-tool",
                arguments = new { input = "hello" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        var content = body.GetProperty("result")
                         .GetProperty("content")[0];
        Assert.Equal("text", content.GetProperty("type").GetString());
    }

    private async Task InitializeAsync()
    {
        var init = new { jsonrpc = "2.0", id = 0, method = "initialize",
            @params = new { protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test", version = "1.0" } } };
        await _client.PostAsJsonAsync("/mcp", init);
    }
}
```

### Key points

- **`WebApplicationFactory<Program>`** boots your real middleware pipeline in-memory — no ports, no process management.
- Override services in the factory (e.g., swap a DB for an in-memory one) via `factory.WithWebHostBuilder(b => b.ConfigureServices(...))`.
- If your MCP server uses **SSE streaming**, read the response stream incrementally with `HttpCompletionOption.ResponseHeadersRead` and parse `text/event-stream` lines.
- Make `Program` visible to tests by adding `[assembly: InternalsVisibleTo("YourTests")]` or a `public partial class Program { }` marker.
